{"npsn":"103086","name":"STIKES Tengku Maharatu","address":"Jalan Kaswari No 10 A-D Sukajadi\nJalan Soekarno Hatta no.98 Pekanbaru","village":"Tuahkarya","status":"Swasta","jenjang":"UNIVERSITAS","district":"Tuahmadani","regencyBpsCode":"1471","regencyName":"Kota Pekanbaru","provinceName":"Riau","school_id":"a13fe5cc-4200-414a-a5a7-75dfa1e4b5d5","user_id":"9dba9fe1-9860-4e9e-8ae3-9928a41e5752","password_hash":"$2b$04$N0lM2NHbT9XVvMmOYO1vZuf.228eGUIXeZ50SQ8MBR9iGTdnbwvPy"},
{"npsn":"101007","name":"Universitas Lancang Kuning","address":"Jalan Yos Sudarso Km 8 Rumbai, Pekanbaru, Riau, Indonesia","village":"Sidomulyo Barat","status":"Swasta","jenjang":"UNIVERSITAS","district":"Tuahmadani","regencyBpsCode":"1471","regencyName":"Kota Pekanbaru","provinceName":"Riau","school_id":"4ba76c41-9bbc-4d43-9aa5-99bdb8a8d847","user_id":"71283191-c5e9-49df-992c-b39f500a80b5","password_hash":"$2b$04$N0lM2NHbT9XVvMmOYO1vZuS1/mOBukjvw0DiR2ETeKxH8ck2SIp/y"},
{"npsn":"104088","name":"Akademi Analis Kesehatan Pekanbaru","address":"Jalan Riau Ujung No 73","village":"Simpangbaru","status":"Swasta","jenjang":"UNIVERSITAS","district":"Binawidya","regencyBpsCode":"1471","regencyName":"Kota Pekanbaru","provinceName":"Riau","school_id":"3a204470-47a4-4ed3-b0a8-6592691349c8","user_id":"583422d6-4f8f-419d-acbb-3b52aa5fad53","password_hash":"$2b$04$N0lM2NHbT9XVvMmOYO1vZunjWwoM743LX5etZQ5x5lP.rwRmO7PKG"}
]'::json;
BEGIN
    PERFORM set_config('statement_timeout', '120000', true);

    -- 1. Insert schools
    INSERT INTO public.schools (id, name, npsn, location, accreditation, regency_id)
    SELECT 
        (x.school_id)::uuid, 
        x.name, 
        x.npsn, 
        concat_ws(', ', nullif(x.address, ''), nullif(x.village, ''), nullif(x.district, ''), nullif(x."regencyName", ''), x."provinceName"),
        'C',
        r.id
    FROM json_to_recordset(v_data) AS x(
        school_id text, name text, npsn text, address text, village text, district text, "regencyName" text, "regencyBpsCode" text, "provinceName" text
    )
    JOIN public.regencies r ON r.code = x."regencyBpsCode"
    WHERE NOT EXISTS (SELECT 1 FROM public.schools s WHERE s.npsn = x.npsn);

    -- 2. Insert auth.users
    INSERT INTO auth.users (
        instance_id, id, aud, role, email, encrypted_password, 
        email_confirmed_at, recovery_sent_at, last_sign_in_at, 
        raw_app_meta_data, raw_user_meta_data, created_at, updated_at, 
        confirmation_token, email_change, email_change_token_new, recovery_token
    )
    SELECT 
        '00000000-0000-0000-0000-000000000000'::uuid, 
        (x.user_id)::uuid, 
        'authenticated', 
        'authenticated', 
        x.npsn || '@mail.com', 
        x.password_hash, 
        now(), now(), now(), 
        json_build_object('provider', 'email', 'providers', json_build_array('email'))::jsonb, 
        '{}'::jsonb, 
        now(), now(), '', '', '', ''
    FROM json_to_recordset(v_data) AS x(
        user_id text, npsn text, password_hash text
    )
    WHERE NOT EXISTS (SELECT 1 FROM auth.users u WHERE u.email = x.npsn || '@mail.com');

    -- 3. Insert auth.identities
    INSERT INTO auth.identities (
        id, user_id, provider_id, identity_data, provider, last_sign_in_at, created_at, updated_at
    )
    SELECT 
        (x.user_id)::uuid, 
        (x.user_id)::uuid, 
        x.user_id, 
        json_build_object('sub', x.user_id, 'email', x.npsn || '@mail.com')::jsonb, 
        'email', 
        now(), now(), now()
    FROM json_to_recordset(v_data) AS x(
        user_id text, npsn text
    )
    WHERE NOT EXISTS (SELECT 1 FROM auth.identities i WHERE i.id = (x.user_id)::uuid);

    -- 4. Insert public.profiles
    INSERT INTO public.profiles (id, role, school_id, created_at)
    SELECT 
        (x.user_id)::uuid, 
        'SCHOOL', 
        (x.school_id)::uuid, 
        now()
    FROM json_to_recordset(v_data) AS x(
        user_id text, school_id text, npsn text
    )
    WHERE NOT EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = (x.user_id)::uuid);
END $$;
